def process_data(data, mode, flag1, flag2, flag3):
    result = []
    if mode == 'a':
        if flag1:
            if data:
                for item in data:
                    if item > 0:
                        if flag2:
                            result.append(item * 2)
                        else:
                            if flag3:
                                result.append(item * 3)
                            else:
                                result.append(item)
                    else:
                        result.append(0)
            else:
                return []
        else:
            return None
    elif mode == 'b':
        result = [x for x in data if x > 0]
    else:
        pass
    return result

