use collections::Stack;

#[test]
fn test_push_pop() {
    let mut s = Stack::new();
    s.push(1);
    s.push(2);
    assert_eq!(s.pop(), Some(2));
    assert_eq!(s.pop(), Some(1));
}

#[test]
fn test_peek() {
    let mut s = Stack::new();
    s.push(42);
    assert_eq!(s.peek(), Some(&42));
    assert_eq!(s.pop(), Some(42));
}

#[test]
fn test_is_empty() {
    let mut s: Stack<i32> = Stack::new();
    assert!(s.is_empty());
    s.push(1);
    assert!(!s.is_empty());
}

#[test]
fn test_len() {
    let mut s = Stack::new();
    assert_eq!(s.len(), 0);
    s.push(1);
    s.push(2);
    assert_eq!(s.len(), 2);
}

#[test]
fn test_clear() {
    let mut s = Stack::new();
    s.push(1);
    s.push(2);
    s.clear();
    assert!(s.is_empty());
    assert_eq!(s.len(), 0);
}
